mapper.update:
MERGE INTO TB_BOX_IVT_ENPR_INFO_D tbieid
    USING DUAL ON (tbieid.UTLINSTT_ID = #{utlinsttId})
WHEN MATCHED THEN
    UPDATE SET
        RCMD_ENPR_STUP_YN   = #{rcmdEnprStupYn}
        , AMNN_USER_ID      = #{amnnUserId}
        , AMNN_TS           = CURRENT_TIMESTAMP
WHEN NOT MATCHED THEN
    INSERT
    (
        UTLINSTT_ID
        , RCMD_ENPR_STUP_YN
        , RGSN_USER_ID
        , RGSN_TS
        , AMNN_USER_ID
        , AMNN_TS
    )
    VALUES
    (
        #{utlinsttId}
        , #{rcmdEnprStupYn}
        , #{rgsnUserId}
        , CURRENT_TIMESTAMP
        , #{amnnUserId}
        , CURRENT_TIMESTAMP
    )
